#include <stdio.h>
#include <stdlib.h>

int main() {
    FILE *src, *dest;
    int ch;

    src = fopen("source.txt", "r");
    if (src == NULL) {
        printf("Cannot open source file\n");
        exit(1);
    }

    dest = fopen("destination.txt", "w");
    if (dest == NULL) {
        printf("Cannot open destination file\n");
        fclose(src);
        exit(1);
    }

    while ((ch = fgetc(src)) != EOF) {
        fputc(ch, dest);
    }

    if (ferror(src)) {
        printf("Error reading source file\n");
    }

    fclose(src);
    fclose(dest);
    printf("File copied successfully\n");
    return 0;
}

#include <stdio.h>

int main() {
    FILE *fp;
    char ch;
    int lineCount = 0;

    fp = fopen("data.txt", "r");
    if (fp == NULL) {
        printf("File cannot be opened\n");
        return 1;
    }

    while ((ch = fgetc(fp)) != EOF) {
        if (ch == '\n') {
            lineCount++;
        }
    }

    // Check if file was non-empty and last line had no newline
    if (ftell(fp) > 0 && ch != '\n') {
        lineCount++;
    }

    fclose(fp);
    printf("Number of lines: %d\n", lineCount);
    return 0;
}

#include <stdio.h>
#include <string.h>

struct Student {
    char name[50];
    int rollNo;
    float marks;
};

void writeRecords() {
    FILE *fp;
    struct Student s;

    fp = fopen("student.dat", "w");
    if (fp == NULL) {
        printf("Error opening file\n");
        return;
    }

    printf("Enter name, roll no, marks: ");
    while (scanf("%s %d %f", s.name, &s.rollNo, &s.marks) == 3) {
        fprintf(fp, "%s %d %.2f\n", s.name, s.rollNo, s.marks);
    }

    fclose(fp);
}

void readRecords() {
    FILE *fp;
    struct Student s;

    fp = fopen("student.dat", "r");
    if (fp == NULL) {
        printf("Error opening file\n");
        return;
    }

    printf("\nStudent Records:\n");
    while (fscanf(fp, "%s %d %f", s.name, &s.rollNo, &s.marks) == 3) {
        printf("Name: %s, Roll: %d, Marks: %.2f\n", 
               s.name, s.rollNo, s.marks);
    }

    fclose(fp);
}

int main() {
    writeRecords();
    readRecords();
    return 0;
}

#include <stdio.h>
#include <string.h>

struct Student {
    char name[50];
    int rollNo;
    float marks;
};

int searchByRoll(FILE *fp, int searchRoll) {
    struct Student s;
    int found = 0;

    rewind(fp);  // Start from beginning

    while (fscanf(fp, "%s %d %f", s.name, &s.rollNo, &s.marks) == 3) {
        if (s.rollNo == searchRoll) {
            printf("Found: %s %d %.2f\n", s.name, s.rollNo, s.marks);
            found = 1;
            break;
        }
    }

    return found;
}

int main() {
    FILE *fp;
    int searchRoll, result;

    fp = fopen("student.dat", "r");
    if (fp == NULL) {
        printf("File not found\n");
        return 1;
    }

    printf("Enter roll number to search: ");
    scanf("%d", &searchRoll);

    result = searchByRoll(fp, searchRoll);

    if (!result) {
        printf("Record not found\n");
    }

    fclose(fp);
    return 0;
}
